# Running Applications and Localized System Configuration Files

## Overview

Applications interact with system configuration files through standard file I/O operations by locating, opening, reading/parsing, and sometimes writing configuration data stored in well-defined filesystem locations.

---

## File Location Strategies

### 1. Standard Search Path Hierarchy

```c
// C example: searching config in priority order
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

const char *config_search_paths[] = {
    "./app.conf",                    // Current directory (highest priority)
    "~/.config/myapp/app.conf",      // User-specific config
    "/etc/myapp/app.conf",           // System-wide config
    "/usr/share/myapp/app.conf",     // Default/fallback config
    NULL
};

FILE *find_config_file(void) {
    for (int i = 0; config_search_paths[i] != NULL; i++) {
        // Expand ~ to home directory
        char expanded[512];
        if (config_search_paths[i][0] == '~') {
            const char *home = getenv("HOME");
            snprintf(expanded, sizeof(expanded), "%s%s", 
                     home, config_search_paths[i] + 1);
        } else {
            strncpy(expanded, config_search_paths[i], sizeof(expanded));
        }

        FILE *f = fopen(expanded, "r");
        if (f != NULL) {
            fprintf(stderr, "Using config: %s\n", expanded);
            return f;
        }
    }
    return NULL;  // No config found
}
```

### 2. Environment Variable Override

```python
import os
import configparser

def resolve_config_path(app_name: str) -> str:
    """Resolve config path with environment variable override."""

    # 1. Check explicit override
    env_override = os.environ.get(f"{app_name.upper()}_CONFIG")
    if env_override:
        return env_override

    # 2. XDG Base Directory Specification (Linux standard)
    xdg_config_home = os.environ.get(
        "XDG_CONFIG_HOME", 
        os.path.expanduser("~/.config")
    )

    user_config = os.path.join(xdg_config_home, app_name, "config.ini")
    if os.path.exists(user_config):
        return user_config

    # 3. XDG system-wide paths
    xdg_config_dirs = os.environ.get(
        "XDG_CONFIG_DIRS", 
        "/etc/xdg"
    ).split(":")

    for config_dir in xdg_config_dirs:
        system_config = os.path.join(config_dir, app_name, "config.ini")
        if os.path.exists(system_config):
            return system_config

    raise FileNotFoundError(f"No config file found for {app_name}")
```

